mapper.sql:
WHERE C.symbol = #{symbol}
  AND C.depth  = #{depth}
  AND C.wave_start BETWEEN #{barDateTimeMin} AND #{barDateTimeMax}
AND C.wave = #{wave}
AND P.wave = #{previousWave}
AND N.wave = #{nextWave}
AND N2.wave = #{next2Wave}
AND T4H.wave = #{wave4h}

mapper.select:
SELECT C.symbol AS symbol ,C.depth AS depth ,C.wave_start AS curWaveStart ,C.wave_end AS curWaveEnd ,C.wave AS curWave ,C.resistance AS curResistance ,C.support AS curSupport ,COALESCE(cur4h200s.sma_price, 0) AS curSma4h200sS ,COALESCE(cur4h200e.sma_price, 0) AS curSma4h200sE ,COALESCE(cur4h75s.sma_price, 0) AS curSma4h75sS ,COALESCE(cur4h75e.sma_price, 0) AS curSma4h75sE ,COALESCE(cur4h20s.sma_price, 0) AS curSma4h20sS ,COALESCE(cur4h20e.sma_price, 0) AS curSma4h20sE ,COALESCE(cur1h200s.sma_price, 0) AS curSma1h200sS ,COALESCE(cur1h200e.sma_price, 0) AS curSma1h200sE ,COALESCE(cur15m200s.sma_price, 0) AS curSma15m200sS ,COALESCE(cur15m200e.sma_price, 0) AS curSma15m200sE ,T4H.wave_start AS t4hWaveStart ,T4H.wave_end AS t4hWaveEnd ,COALESCE(T4H.wave, 0) AS t4hWave ,COALESCE(T4H.resistance, 0) AS t4hResistance ,COALESCE(T4H.support, 0) AS t4hSupport ,COALESCE(t4h4h200s.sma_price, 0) AS t4hSma4h200sS ,COALESCE(t4h4h200e.sma_price, 0) AS t4hSma4h200sE ,COALESCE(t4h4h75s.sma_price, 0) AS t4hSma4h75sS ,COALESCE(t4h4h75e.sma_price, 0) AS t4hSma4h75sE ,COALESCE(t4h4h20s.sma_price, 0) AS t4hSma4h20sS ,COALESCE(t4h4h20e.sma_price, 0) AS t4hSma4h20sE ,COALESCE(t4h1h200s.sma_price, 0) AS t4hSma1h200sS ,COALESCE(t4h1h200e.sma_price, 0) AS t4hSma1h200sE ,COALESCE(t4h15m200s.sma_price, 0) AS t4hSma15m200sS ,COALESCE(t4h15m200e.sma_price, 0) AS t4hSma15m200sE ,P.wave_start AS prvWaveStart ,P.wave_end AS prvWaveEnd ,P.wave AS prvWave ,P.resistance AS prvResistance ,P.support AS prvSupport ,N.wave_start AS nxtWaveStart ,N.wave_end AS nxtWaveEnd ,N.wave AS nxtWave ,N.resistance AS nxtResistance ,N.support AS nxtSupport ,N2.wave_start AS nx2WaveStart ,N2.wave_end AS nx2WaveEnd ,N2.wave AS nx2Wave ,N2.resistance AS nx2Resistance ,N2.support AS nx2Support ,COALESCE(dxy4h.wave, 0) AS waveDxy4h ,COALESCE(dxy1h.wave, 0) AS waveDxy1h
ORDER BY C.wave_start DESC
LIMIT #{size} LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM fx_bar_${barType}
WHERE symbol = #{symbol}
  AND bar_date_time >= #{barDateTime}

SELECT

    ,B.high_price   AS barHighPrice
    ,B.low_price    AS barLowPrice
    ,B.close_price  AS barClosePrice
    ,1              AS existsZigzag
FROM fx_zigzag_${barType} Z
INNER JOIN fx_bar_${barType} B
       ON B.symbol = Z.symbol AND B.bar_date_time = Z.bar_date_time
WHERE Z.symbol = #{symbol}
  AND Z.depth  = #{depth}
  AND Z.bar_date_time < #{barDateTime}
ORDER BY Z.bar_date_time DESC
LIMIT #{limit}

mapper.update:
UPDATE fx_zigzag_${barType} SET
    resistance                       = #{e.resistance}
   ,resistance_fractal               = #{e.resistanceFractal}
   ,support                          = #{e.support}
   ,support_fractal                  = #{e.supportFractal}
   ,high                             = #{e.priceHigh}
   ,low                              = #{e.priceLow}
   ,backstep_high                    = #{e.backStepHigh}
   ,backstep_low                     = #{e.backStepLow}
   ,fractal_high                     = #{e.fractalHigh}
   ,fractal_low                      = #{e.fractalLow}
   ,resistance_bar_date_time         = #{e.resistanceBarDateTime}
   ,resistance_fractal_bar_date_time = #{e.resistanceFractalBarDateTime}
   ,support_bar_date_time            = #{e.supportBarDateTime}
   ,support_fractal_bar_date_time    = #{e.supportFractalBarDateTime}
   ,high_bar_date_time               = #{e.priceHighBarDateTime}
   ,low_bar_date_time                = #{e.priceLowBarDateTime}
   ,backstep_high_bar_date_time      = #{e.backStepHighBarDateTime}
   ,backstep_low_bar_date_time       = #{e.backStepLowBarDateTime}
   ,backstep_up                      = #{e.backStepUp}
   ,backstep_down                    = #{e.backStepDown}
   ,wave                             = #{e.wave}
   ,up_trend                         = #{e.upTrend}
   ,break_resistance                 = #{e.breakResistance}
   ,break_support                    = #{e.breakSupport}
WHERE symbol       = #{e.symbol}
  AND depth        = #{e.depth}
  AND bar_date_time = #{e.barDateTime}

mapper.delete:
DELETE FROM fx_zigzag_wave_${barType}
WHERE symbol    = #{symbol}
  AND depth     = #{depth}
  AND wave_start >= #{barDateTime}
